/* Compute the reverse prefix sum of the vector `x` into `output`.
 *   result[i] = sum_{j=i}^{x.size()-1} x[j]
 *
 * The function preserves the original behaviour (including the order
 * of elements and the use of 32‑bit signed integer arithmetic.
 * It runs in linear time without allocating auxiliary buffers.
 */
void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {
    const std::size_t n = x.size();

    /* Ensure that the output vector has the correct size.  The
     * harness guarantees that `output` has space for `n` elements,
     * but resizing it here is harmless and defensive.           */
    if (output.size() < n)
        output.resize(n);

    if (n == 0) return;

    int sum = 0;
    /* Compute the cumulative sum in reverse order.  This is
     * equivalent to an inclusive scan on the reversed array, but
     * without allocating a temporary vector.                     */
    for (std::size_t i = n; i-- > 0; ) {
        sum += x[i];
        output[i] = sum;
    }
}
