/* Compute the prefix sum array of the vector `x` and return its sum.
   This implementation uses the mathematical identity
        sum_{i=0}^{n-1} (sum_{j=0}^{i} x[j]) = Σ_{j=0}^{n-1} x[j] * (n-j)
   which allows a single linear‑time and fully parallel reduction.
   Example:
       input: [-7, 2, 1, 9, 4, 8]
       output: 15
*/
int64_t sumOfPrefixSum(std::vector<int64_t> const& x) {
    const std::size_t n = x.size();
    if (n == 0) return 0;

    // Parallel reduction using OpenMP.
    // Each thread computes a partial sum over its chunk.
    int64_t total = 0;
    #pragma omp parallel
    {
        int64_t local = 0;
        #pragma omp for nowait
        for (std::size_t i = 0; i < n; ++i) {
            local += static_cast<int64_t>(x[i]) * static_cast<int64_t>(n - i);
        }
        #pragma omp atomic
        total += local;
    }
    return total;
}
