/* Return the sum of the minimum value at each index of vectors x and y for all indices.
   i.e. sum = min(x_0, y_0) + min(x_1, y_1) + min(x_2, y_2) + ...
   Example:
   input: x=[3, 4, 0, 2, 3], y=[2, 5, 3, 1, 7]
   output: 10
*/
inline int64_t sumOfMinimumElements(const std::vector<int64_t> &x,
                                    const std::vector<int64_t> &y) noexcept
{
    const std::size_t n = x.size();
    // Safety: Assume x and y are of equal size. If not, take the minimum length.
    std::size_t m = y.size();
    const std::size_t len = (n < m ? n : m);
    if (len == 0)
        return 0;

    int64_t total = 0;
#pragma omp parallel for reduction(+:total) schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(len); ++i)
    {
        const int64_t a = x[i];
        const int64_t b = y[i];
        total += (a < b ? a : b);
    }
    return total;
}
