/*
 * In the vector 'x' negate the odd values and divide the even values by 2.
 * Example:
 * input : [16, 11, 12, 14, 1, 0, 5]
 * output: [8,  -11, 6, 7, -1, 0, -5]
 *
 * The implementation is fully thread‑safe, uses a parallel for loop
 * and operates directly on the vector without creating temporary
 * containers, thereby minimizing memory traffic and CPU stalls.
 */
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();
    if(n == 0) return;

    /* Parallel loop with static scheduling.
     * The work is evenly split among threads and local computations
     * avoid false sharing because each element is independent.
     */
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        const int val = x[static_cast<std::size_t>(i)];
        /* For negative even numbers integer division truncates toward
         * zero (e.g. -3 / 2 == -1), which matches the behaviour of the
         * original std::transform implementation. */
        if ((val & 1) == 0) {          // even
            x[static_cast<std::size_t>(i)] = val / 2;
        } else {                       // odd
            x[static_cast<std::size_t>(i)] = -val;
        }
    }
}
