/*
 * Count strings per starting letter.
 * Parallel version: each thread builds a private bin array
 * and the results are summed into the output `bins`.
 */
void firstLetterCounts(std::vector<std::string> const& s,
                       std::array<size_t, 26> &bins)
{
    constexpr int ALPHA = 26;
    const int N      = int(s.size());
    const int nThreads = omp_get_max_threads();

    /* per‑thread private bin arrays */
    std::vector<std::array<size_t, ALPHA>> localBins(nThreads);
    for (int t = 0; t < nThreads; ++t) {
        localBins[t].fill(0);
    }

    /* parallel loop: each thread updates its own bin array */
    #pragma omp parallel
    {
        const int t = omp_get_thread_num();
        auto &lb = localBins[t];

        #pragma omp for
        for (int i = 0; i < N; ++i) {
            const char c = s[i][0];
            const int  idx = static_cast<int>(c - 'a');
            /* idx is guaranteed 0..25 in the problem statement */
            ++lb[idx];
        }
