struct COOElement {
   size_t row, column;
   double value;
};

/*
 * Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
 * and A is a sparse matrix stored in COO format.
 * x and y are length N and A is M x N.
 *
 * Example:
 *   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
 *   output: y=[2, 3]
 */
inline void spmv(double alpha,
                 const std::vector<COOElement>& A,
                 const std::vector<double>& x,
                 double beta,
                 std::vector<double>& y,
                 size_t M,
                 size_t N)
{
   // Scale y by beta -- thread‑safe as each thread works on distinct elements
   #pragma omp parallel for schedule(static)
   for (size_t i = 0; i < y.size(); ++i) {
      y[i] *= beta;
   }

   // Add contribution from each non‑zero element
   // Use atomic addition to avoid race conditions when multiple elements
   // update the same row of y
   #pragma omp parallel for schedule(static)
   for (size_t k = 0; k < A.size(); ++k) {
      const COOElement& e = A[k];
      if (e.row < M && e.column < N) {
         const double prod = alpha * e.value * x[e.column];
         #pragma omp atomic
         y[e.row] += prod;
      }
   }
}
