#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

// Helper: build a map from row index of X to its non‑zeros
static std::unordered_map<size_t, std::vector<COOElement>>
build_row_map(const std::vector<COOElement>& X)
{
    std::unordered_map<size_t, std::vector<COOElement>> map;
    map.reserve(X.size() * 2);
    for (const auto& e : X)
        map[e.row].push_back(e);
    return map;
}

/* Compute Y = A * X (sparse * sparse → dense)
   Y is M×N dense matrix stored row‑major.
   A: M×K sparse, COO
   X: K×N sparse, COO
   Uses parallelism with OpenMP, exploiting the fact that A is much sparser.
*/
inline void spmm(const std::vector<COOElement>& A,
                 const std::vector<COOElement>& X,
                 std::vector<double>& Y,
                 size_t M, size_t K, size_t N)
{
    Y.assign(M * N, 0.0);

    auto row_map = build_row_map(X);            // X elements indexed by source row

    // Parallel over A entries; each thread updates Y independently using atomics
    #pragma omp parallel
    {
        const size_t chunk = omp_get_num_threads();
        const size_t thread_id = omp_get_thread_num();
        const size_t len = A.size();
        for (size_t i = thread_id; i < len; i += chunk) {
            const auto& a = A[i];
            auto it = row_map.find(a.column);
            if (it == row_map.end()) continue;  // no matching row in X

            const std::vector<COOElement>& vec = it->second;
            size_t base = a.row * N;
            for (const auto& x : vec) {
                const size_t idx = base + x.column;
                #pragma omp atomic
                Y[idx] += a.value * x.value;
