#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstddef>
#include <omp.h>

#if !defined(M_PI)
#   define M_PI 3.14159265358979323846
#endif

/* Compute the discrete Fourier transform of x.
   The result is stored in output. The function uses
   O(N²) operations as the original implementation
   but parallelises over the output indices and
   employs a recurrence to avoid repeated calls to
   std::cos and std::sin for each multiplication.
   The behaviour (numerical output) is identical
   to the simply‑structured code.
*/
void dft(const std::vector<double> &x,
         std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    const double two_pi = 2.0 * M_PI;
    const double invN   = 1.0 / static_cast<double>(N);

    /* parallel over the output index k */
    #pragma omp parallel for schedule(static)
    for (long long k = 0; k < static_cast<long long>(N); ++k) {
        std::complex<double> sum(0.0, 0.0);

        /* twiddle factor: w = exp(-2πi * k / N) */
        double angle_factor = two_pi * static_cast<double>(k) * invN;
        double cr = std::cos(angle_factor);
        double ci = std::sin(angle_factor);            // note sign: sin(angle_factor) is positive
        // w = cos - i sin
        std::complex<double> w(cr, -ci);

        std::complex<double> phase(1.0, 0.0);

        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * phase;
            phase *= w;   // advance to the next twiddle factor
        }

        output[k] = sum;
    }
}
