// optimized implementation of solveLinearSystem
#pragma once
#include <cmath>      // std::abs
#include <vector>
#include <algorithm>  // std::swap

struct COOElement {
    size_t row, column;
    double value;
};

void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double>& x,
                       size_t N)
{
    // allocate a flat N×N matrix to reduce indirection
    std::vector<double> mat(N * N, 0.0);
    auto idx = [N](size_t r, size_t c) { return r * N + c; };

    // fill matrix with COO data
    for (auto const& e : A) {
        mat[idx(e.row, e.column)] = e.value;
    }

    // copy vector b
    std::vector<double> rhs = b;
    x.assign(N, 0.0);

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // pivot search
        size_t maxRow = i;
        double maxVal = std::abs(mat[idx(i, i)]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(mat[idx(k, i)]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }

        // swap rows i and maxRow
        if (maxRow != i) {
            for (size_t c = 0; c < N; ++c) {
                std::swap(mat[idx(i, c)], mat[idx(maxRow, c)]);
            }
            std::swap(rhs[i], rhs[maxRow]);
        }

        // zero out below pivot
        double pivot = mat[idx(i, i)];
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -mat[idx(k, i)] / pivot;
            mat[idx(k, i)] = 0.0; // explicit zero
            for (size_t j = i + 1; j < N; ++j) {
                mat[idx(k, j)] += factor * mat[idx(i, j)];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    // back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j) {
            sum -= mat[idx(i, j)] * x[j];
        }
        x[i] = sum / mat[idx(i, i)];
    }
}
