#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/*
 * Sparse LU factorisation (no pivoting).  The caller guarantees that
 * all diagonal entries of `A` are non‑zero, so the factorisation is
 * exact.  The result is stored in flat row‑major arrays `L` and
 * `U`.  The input matrix `A` is kept untouched.
 *   L[i*N + j]  – lower‑triangular part (unit diagonal)
 *   U[i*N + j]  – upper‑triangular part
 */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double> &L,
                 std::vector<double> &U,
                 size_t N)
{
   // Allocate result matrices and a dense cache for quick lookup
   L.assign(N * N, 0.0);
   U.assign(N * N, 0.0);

   // Build a hash map for fast access to matrix entries
   std::unordered_map<size_t, double> aMap;
   aMap.reserve(A.size() * 2);
   for (auto const& e : A)
       aMap[(e.row << 32) | e.column] = e.value;

   // Helper to fetch a value from the sparse matrix (zero if missing)
   auto getA = [&](size_t i, size_t j) -> double {
       auto it = aMap.find((i << 32) | j);
       return it != aMap.end() ? it->second : 0.0;
   };

   /*  Parallel outer loop – each iteration only touches rows
     below i for the next step, so we can safely parallelise.
   */
   #pragma omp parallel for schedule(static)
   for (int i = 0; i < static_cast<int>(N); ++i) {
       // Upper part (j >= i)
       for (size_t j = i; j < N; ++j) {
           double val = getA(i, j);
           for (size_t k = 0; k < i; ++k) {
               val -= L[i * N + k] * U[k * N + j];
           }
           U[i * N + j] = val;
       }

       // Lower part (j < i)
       for (size_t j = 0; j < i; ++j) {
           double val = getA(i, j);
           for (size_t k = 0; k < j; ++k) {
               val -= L[i * N + k] * U[k * N + j];
           }
           L[i * N + j] = val / U[j * N + j];
       }

       // Unit diagonal of L
       L[i * N + i] = 1.0;
   }
}
