/* Optimised in‑place Radix‑2 FFT (Cooley‑Tukey) with OpenMP parallelism.
   - Keeps exactly the same semantics as the original function.
   - Uses a pre‑computed vector of twiddle factors per stage.
   - Bit‑reverses the indices first, then performs butterfly stages.
   - Parallelises the final copy of the complex vector into the real/imaginary arrays.
*/
void fft(std::vector<std::complex<double>> const& x, std::vector<double> &r, std::vector<double> &i) {
    const std::size_t N = x.size();
    std::vector<std::complex<double>> data(x);            // copy input
    // --- Bit-reversal permutation ------------------------------------------------
    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i) {
        if (i < rev) std::swap(data[i], data[rev]);
        std::size_t mask = N;
        while (rev & (mask >>= 1)) rev ^= mask;
        rev |= mask;
    }

    // --- FFT stages ---------------------------------------------------------------
    for (std::size_t len = 2; len <= N; len <<= 1) {
        const std::size_t half = len >> 1;
        const double angle = -M_PI / half;
        const std::complex<double> wlen = std::exp(std::complex<double>(0.0, angle));

        // Pre‑compute twiddle factors for this stage
        std::vector<std::complex<double>> ws(half);
        ws[0] = 1.0;
        for (std::size_t j = 1; j < half; ++j) ws[j] = ws[j-1] * wlen;

        // Butterfly operations (outer loop can be parallelised)
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len) {
            for (std::size_t j = 0; j < half; ++j) {
                const std::complex<double> u = data[i + j];
                const std::complex<double> v = data[i + j + half] * ws[j];
                data[i + j]         = u + v;
                data[i + j + half]  = u - v;
            }
        }
    }

    // --- Copy to output (parallel) ------------------------------------------------
    r.resize(N);
    i.resize(N);
    #pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < N; ++idx) {
        r[idx] = data[idx].real();
        i[idx] = data[idx].imag();
    }
}
