#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <algorithm>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of the vector `x` into `output`.
 *
 * The implementation performs a two‑pass parallel scan:
 *   1. Each thread computes the inclusive scan of its chunk and the sum
 *      of that chunk.
 *   2. The sums of all chunks are scanned sequentially.
 *   3. The per‑chunk scans are offset by the cumulative sum of the
 *      preceding chunks.
 *
 * This preserves the exact result of std::inclusive_scan but exploits
 * the available 8 threads for speed.
 */
void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t> &output) {
    std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    // Allocate space for per-block sums
    int num_threads = 8;                       // Up to the target platform
    std::vector<int64_t> blockSums(num_threads, 0);

    // First pass: per-thread inclusive scan and block sums
    #pragma omp parallel num_threads(num_threads)
    {
        int id = omp_get_thread_num();
        std::size_t start = (n * id) / num_threads;
        std::size_t end   = (n * (id + 1)) / num_threads;

        if (start == end) return; // No work for this thread

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        blockSums[id] = sum;
    }

    // Second pass: compute the prefix of block sums sequentially
    for (int i = 1; i < num_threads; ++i) {
        blockSums[i] += blockSums[i - 1];
    }

    // Third pass: offset each block by the sum of the preceding blocks
    #pragma omp parallel for schedule(static)
    for (int id = 0; id < num_threads; ++id) {
        std::size_t start = (n * id) / num_threads;
        std::size_t end   = (n * (id + 1)) / num_threads;
        if (start == end) continue;

        // Offset by the sum of all previous blocks
        int64_t offset = (id == 0) ? 0 : blockSums[id - 1];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
