// ------------------------------------------------------------
// 8‑thread optimized Cooley‑Tukey radix‑2 FFT (in‑place)
// ------------------------------------------------------------
inline void fft(std::vector<std::complex<double> > const& x,
                std::vector<std::complex<double> >& output)
{
    const std::size_t N = x.size();
    assert((N & (N - 1)) == 0 && "size must be a power of two");

    // copy input
    output = x;

    // pre‑compute twiddle factors for the entire transform
    std::vector<std::complex<double>> twiddles(N/2);
    const double two_pi = 2.0 * M_PI;
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N/2; ++i)
        twiddles[i] = std::polar(1.0, -two_pi * i / N);

    // iterative butterfly (bit‑reverse order already handled later)
    std::size_t half = 1;
    while (half < N) {
        const std::size_t step = half << 1;
        const double theta = -M_PI / half;            // = -2π / step
        const std::complex<double> w_m = std::polar(1.0, theta);

        #pragma omp parallel for schedule(static, 1024)
        for (std::size_t k = 0; k < half; ++k) {
            std::complex<double> w = 1.0;
            for (std::size_t j = k; j < N; j += step) {
                const std::size_t l = j + half;
                const std::complex<double> t = output[l] * w;
                output[l] = output[j] - t;
                output[j] += t;
                w *= w_m;
            }
        }
        half = step;
    }

    // Bit‑reversal permutation
    const std::size_t log_n = static_cast<std::size_t>(std::log2(N));
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        // reverse bits of i
        std::size_t j = 0;
        std::size_t m = i;
        for (std::size_t k = 0; k < log_n; ++k) {
            j = (j << 1) | (m & 1);
            m >>= 1;
        }
        if (j > i) std::swap(output[i], output[j]);
    }
}
