    std::vector<Point> h;
    h.reserve(2 * n);

    // lower hull
    for (size_t i = 0; i < n; ++i)
    {
        while (h.size() >= 2 &&
               cross(h[h.size() - 2], h[h.size() - 1], v[i]) <= 0)
            h.pop_back();
        h.push_back(v[i]);
    }

    // upper hull
    for (size_t i = n - 1; i > 0; --i)
    {
        while (h.size() > n &&
               cross(h[h.size() - 2], h[h.size() - 1], v[i - 1]) <= 0)
            h.pop_back();
        h.push_back(v[i - 1]);
    }

    // Last point is same as first; remove it
    h.pop_back();

    double perim = 0.0;
    for (size_t i = 0; i < h.size(); ++i)
        perim += dist(h[i], h[(i + 1) % h.size()]);

    return perim;
}
