```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
   Perform LU factorisation of a square matrix in place.
   A is stored in row-major order.
   Implementation: tiled, vectorised, OpenMP parallelised.
*/
inline void luFactorize(std::vector<double> &A, std::size_t N) {
    // tile size chosen experimentally for balance between cache use and parallelism
    constexpr std::size_t TILE = 64;

    for (std::size_t k = 0; k < N; ++k) {
        const std::size_t kp = k * N;
        double pivot         = A[kp + k];
        double inv_pivot     = 1.0 / pivot;

        // --- compute factors for rows below pivot row ---
        #pragma omp parallel for schedule(static,8) // balance load
        for (std::size_t i = k + 1; i < N; ++i) {
            std::size_t ip = i * N;
            double factor  = A[ip + k] * inv_pivot;
            A[ip + k] = factor;

            // stride two for better vectorisation
            std::size_t j = k + 1;
            for (; j + 3 < N; j += 4) {
                A[ip + j]   -= factor * A[kp + j];
                A[ip + j+1] -= factor * A[kp + j+1];
                A[ip + j+2] -= factor * A[kp + j+2];
                A[ip + j+3] -= factor * A[kp + j+3];
            }
            // handle remaining columns
            for (; j < N; ++j) {
                A[ip + j] -= factor * A[kp + j];
            }
        }
    }
}
