#include <cstdint>
#include <omp.h>

/*  For each cell, count how many of its four orthogonal neighbours contain a 1.
    If the count is exactly one, the result cell is set to 1, otherwise 0.
    The function is fully parallelised with OpenMP and heavily tuned for
    modern x86‑64 CPUs.  The behaviour is identical to the reference
    implementation. */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N) noexcept
{
    // Ensure the output vector has the correct size
    if (output.size() < N*N) output.resize(N*N);

    // Use raw pointers to avoid bounds checking overhead
    const int  *restrict in  = input.data();
    int        *restrict out = output.data();

    const size_t stride = N;

    // Parallelise over rows; each thread works on a contiguous range
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t base = i * stride;           // index of (i,0)
        const bool   up   = (i != 0);
        const bool   down = (i != N-1);

        for (size_t j = 0; j < N; ++j) {
            int count = 0;

            // Check north neighbour
            if (up   && in[base - stride + j]) ++count;   // (i-1, j)
            // Check south neighbour
            if (down && in[base + stride + j]) ++count;   // (i+1, j)
            // Check west neighbour
            if (j != 0 && in[base + j - 1]) ++count;      // (i, j-1)
            // Check east neighbour
            if (j != N-1 && in[base + j + 1]) ++count;    // (i, j+1)

            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
