/*  Rank each element of a vector (stable, generic implementation).
    Complexity: O(n log n) with parallel sorting.
    For each value in the vector x compute its index in the sorted vector.
    Store the results in `ranks_` (exact behavior of the original implementation).
*/
inline void ranks(std::vector<float> const& x, std::vector<size_t>& ranks_)
{
    const size_t n = x.size();
    if (ranks_.size() != n) ranks_.resize(n);

    /*  1. Build indices [0,1,2,...,n-1]  */
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);

    /*  2. Parallel sort indices by the corresponding values of x  */
    __gnu_parallel::sort(
        indices.begin(),
        indices.end(),
        [&](size_t i1, size_t i2) { return x[i1] < x[i2]; }
    );

    /*  3. Write ranks back to the output container  */
    for (size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
