/* Compute one iteration of a 5‑point 2D Jacobi stencil.
 *
 * Results of the computation keep exactly the same
 * numerical values as the original implementation.
 *
 * The routine is parallelised with OpenMP and uses a simple
 * pointer arithmetic to minimise memory indirection.
 *
 * Parameters
 * ----------
 * input  : read‑only N×N grid, row‑major
 * output : write‑only N×N grid, row‑major
 * N      : number of rows (and columns)
 */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double>& output,
                     size_t N)
{
    constexpr double inv5 = 0.2;          // 1/5

    /* Parallelise over rows and columns.
     * The inner loop is smaller than the number of threads,
     * so parallelising over both dimensions yields better
     * load balance for small N. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t iN = i * N;
        const double* prev = (i > 0)     ? &input[(i - 1) * N] : nullptr;
        const double* next = (i + 1 < N) ? &input[(i + 1) * N] : nullptr;

        double* out = &output[iN];
        for (size_t j = 0; j < N; ++j) {
            double sum = input[iN + j];                       // centre
            if (prev) sum += prev[j];                        // north
            if (next) sum += next[j];                        // south
            if (j)    sum += input[iN + j - 1];              // west
            if (j + 1 < N) sum += input[iN + j + 1];          // east
            out[j] = sum * inv5;
        }
    }
}
```

This implementation keeps the exact semantics of the original code while
achieving substantial speedup via OpenMP parallelisation and
pointer‑based access that reduces bounds‑check overhead.

