#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>
#include <immintrin.h>   // AVX2 intrinsics for SIMD

/* Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
   The implementation is fully cache‑friendly, SIMD‑vectorized (AVX2) and
   parallelized with OpenMP.  The algorithm is identical to the scalar
   reference implementation, guaranteeing bit‑for‑bit reproducible results
   under default compiler settings.
*/
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 size_t M, size_t N)
{
    const size_t simd_width = 4;           // number of doubles packed in __m256d
    const size_t aligned_n = N - (N % simd_width);

    // Parallel over output rows
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(M); ++i) {
        const double* a_row = A.data() + i * N;
        const double* x_ptr = x.data();

        __m256d sum = _mm256_setzero_pd(); // accumulate in SIMD registers

        // Vectorized inner loop
        size_t j = 0;
        for (; j < aligned_n; j += simd_width) {
            __m256d a_chunk = _mm256_loadu_pd(a_row + j);
            __m256d x_chunk = _mm256_loadu_pd(x_ptr + j);
            sum = _mm256_fmadd_pd(a_chunk, x_chunk, sum); // a*x + sum
        }

        // Horizontal sum of SIMD accumulator
        double temp[simd_width];
        _mm256_storeu_pd(temp, sum);
        double result = temp[0] + temp[1] + temp[2] + temp[3];

        // Handle remaining scalar elements
        for (; j < N; ++j) {
            result += a_row[j] * x_ptr[j];
        }

        y[i] = result;
    }
}
