/*
 * Find the k-th smallest element of the vector `x`.
 * Example:
 *
 *   input:  x = [1, 7, 6, 0, 2, 2, 10, 6],  k = 4
 *   output: 6
 */
inline int findKthSmallest(const std::vector<int>& x, int k)
{
    // `nth_element` partitions the array so that the element at the
    // requested position is the one that would appear in that
    // position if the array were fully sorted.  All elements before it
    // are less than or equal to it, all elements after it are greater
    // or equal.
    //
    // We copy the data because the input vector is const.  For
    // small vectors this copy has negligible overhead, and the
    // algorithmic gain (O(n) average time vs. O(n log n) of sort)
    // is significant for large inputs.
    std::vector<int> tmp(x.begin(), x.end());

    const size_t idx = static_cast<size_t>(k) - 1;
    std::nth_element(tmp.begin(), tmp.begin() + idx, tmp.end());

    return tmp[idx];
}
