```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Run one Game of Life step.
 *
 * The grid is represented as a single NxN block stored row‑major.
 * Cells contain 0 or 1.  The function preserves the original behaviour
 * while exploiting data parallelism, branch‑elimination and loop
 * blocking for better cache utilisation.
 */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N)
{
    const size_t NN = N * N;
    const int *const restrict in  = input.data();
    int *const restrict out = output.data();

    /* Parallelise the outer loop over rows.
     * The schedule(static,chunk) strategy spreads whole rows over the
     * 8 execution threads while keeping threads contiguous in memory
     * which improves cache locality. */
#pragma omp parallel for schedule(static, 64)
    for (size_t i = 0; i < N; ++i) {
        /* pre‑compute row‑basis pointers */
        size_t idx      = i * N;
        size_t idx_above = idx - N;
        size_t idx_below = idx + N;

        /* process each column */
        for (size_t j = 0; j < N; ++j) {
            /* --- neighbour sum ------------------------------------ */
            int sum = 0;

            /* vertical neighbours */
            if (i > 0)     sum += in[idx_above    + j];
            if (i + 1 < N) sum += in[idx_below    + j];

            /* horizontal neighbours */
            if (j > 0)     sum += in[idx          + j-1];
            if (j + 1 < N) sum += in[idx          + j+1];

            /* diagonal neighbours */
            if (i > 0 && j > 0)      sum += in[idx_above    + j-1];
            if (i > 0 && j + 1 < N)  sum += in[idx_above    + j+1];
            if (i + 1 < N && j > 0)  sum += in[idx_below    + j-1];
            if (i + 1 < N && j + 1 < N) sum += in[idx_below + j+1];

            /* --- game rules -------------------------------------- */
            int cur = in[idx + j];
            /* Branchless evaluation: 1 stays 1 if (sum==2||sum==3),
             * otherwise 0.  A dead cell becomes 1 only if sum==3. */
            int alive = cur * ((sum == 2) | (sum == 3));
            alive |= ((1 - cur) & (sum == 3));
            out[idx + j] = alive;
        }
    }
}
