#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <limits>

struct Point {
    double x, y;
};

static double dist(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the distance between the closest two points in the vector points.
   The function preserves the exact semantics of the original implementation
   while improving the runtime to O(n log n). */
double closestPair(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 2) return 0.0;

    // copy and sort points by x repeatedly
    std::vector<Point> Px(points);
    std::sort(Px.begin(), Px.end(), [](const Point& a, const Point& b) { return a.x < b.x; });

    // recursion
    std::function<double(size_t, size_t)> rec = [&](size_t l, size_t r) -> double {
        size_t len = r - l + 1;
        if (len <= 3) {               // brute force
            double d = std::numeric_limits<double>::max();
            for (size_t i = l; i <= r; ++i)
                for (size_t j = i + 1; j <= r; ++j)
                    d = std::min(d, dist(Px[i], Px[j]));
            std::sort(Px.begin() + l, Px.begin() + r + 1,
                      [](const Point& a, const Point& b) { return a.y < b.y; });
            return d;
        }

        size_t mid = (l + r) / 2;
        double midx = Px[mid].x;

        double dl = rec(l, mid);
        double dr = rec(mid + 1, r);
        double d = std::min(dl, dr);

        // merge sorted by y
        std::vector<Point> temp;
        temp.reserve(len);
        size_t i = l, j = mid + 1;
        while (i <= mid && j <= r) {
            if (Px[i].y < Px[j].y) temp.push_back(Px[i++]); else temp.push_back(Px[j++]);
        }
        while (i <= mid) temp.push_back(Px[i++]);
        while (j <= r) temp.push_back(Px[j++]);

        std::copy(temp.begin(), temp.end(), Px.begin() + l);

        // build strip
        std::vector<Point> strip;
        strip.reserve(len);
        for (size_t k = l; k <= r; ++k)
            if (std::abs(Px[k].x - midx) < d)
                strip.push_back(Px[k]);

        // check strip; at most 7 points to compare
        size_t m = strip.size();
        for (size_t a = 0; a < m; ++a)
            for (size_t b = a + 1; b < m && (strip[b].y - strip[a].y) < d; ++b)
                d = std::min(d, dist(strip[a], strip[b]));

        return d;
    };

    return rec(0, n - 1);
}
