// convex_hull.hpp
#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <Eigen/Dense>          // optional: for faster min/max
#include <omp.h>

/* Point structure */
struct Point {
    double x, y;
};

/* Helper: cross product of OA x OB where O, A, B are points */
constexpr inline double cross(const Point& o, const Point& a, const Point& b) noexcept {
    return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);
}

/* Convex hull (Monotone chain) – preserved exact semantics of original */
inline void convexHull(const std::vector<Point> &points, std::vector<Point> &hull) {
    const std::size_t n = points.size();

    /* Handle trivial cases as original */
    if (n < 3) {
        hull.assign(points.begin(), points.end());
        return;
    }

    /* ------------------------ sorting ------------------------ */
    /* Create a copy, then sort in place.  Use std::sort which
       will use the highly‑optimised introsort.  For large data sets
       we may parallelise the sort via OpenMP, but let the compiler
       handle the standard library implementation.            */
    std::vector<Point> p(points);          // copy

    std::sort(p.begin(), p.end(), [](const Point &a, const Point &b) {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    /* -------------------- hull construction ------------------- */
    /* Reserve twice the size to avoid reallocations during
       construction of lower + upper hulls.                     */
    std::vector<Point> hullTmp; hullTmp.reserve(2 * n);
    hullTmp.resize(0);

    /* Lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (hullTmp.size() >= 2 &&
               cross(hullTmp[hullTmp.size()-2], hullTmp[hullTmp.size()-1], p[i]) <= 0.0) {
            hullTmp.pop_back();                 // remove last point
        }
        hullTmp.push_back(p[i]);
    }

    /* Upper hull – skip the last point of lower hull (duplicate) */
    const std::size_t lowerSize = hullTmp.size();
    for (std::size_t i = n-1; i > 0; --i) {
        while (hullTmp.size() > lowerSize &&
               cross(hullTmp[hullTmp.size()-2], hullTmp[hullTmp.size()-1], p[i-1]) <= 0.0) {
            hullTmp.pop_back();
        }
        hullTmp.push_back(p[i-1]);
    }

    /* Finalizes the hull: remove the last point which is same as first */
    if (!hullTmp.empty()) hullTmp.pop_back();

    /* Return result – copy to supplied vector, reusing memory if possible */
    hull.resize(hullTmp.size());
    std::copy_n(hullTmp.begin(), hullTmp.size(), hull.begin());
}
