#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax = b for x.
   A is an NxN matrix in row‑major order.  The vectors x and b contain N elements.
   The solver performs a straightforward Gaussian elimination with forward elimination
   followed by back substitution.  No pivoting is performed (identical to the original
   implementation), so the caller must ensure that the system is non‑singular.
*/
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              size_t N)
{
    // Allocate continuous copies of A and b to allow pointer arithmetic
    std::vector<double> Acopy(A);   // copy of the matrix
    std::vector<double> bcopy(b);   // copy of the rhs

    // Forward elimination
    for (size_t i = 0; i + 1 < N; ++i) {
        double const* Arow_i = &Acopy[i * N + i];          // pivot row start
        double       pivot  = *Arow_i;                      // A[i][i]
        if (pivot == 0.0) return;                          // singular matrix

        double inv_pivot = 1.0 / pivot;

        // Broadcast the factor computation and elimination over rows j > i
        #pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            double*   Arow_j = &Acopy[j * N + i];
            double   bj     = bcopy[j];
            double   factor = (*Arow_j) * inv_pivot;        // A[j][i] / pivot

            // Subtract factor * pivot_row from row j
            for (size_t k = i; k < N; ++k) {
                Arow_j[k] -= factor * Arow_i[k];
            }
            bcopy[j] = bj - factor * bcopy[i];
        }
    }

    // Back substitution
    // Compute x in place using the already computed upper‑triangular matrix
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j) {
            sum += Acopy[i * N + j] * x[j];
        }
        x[i] = (bcopy[i] - sum) / Acopy[i * N + i];
    }
}
