#pragma once
#include <vector>
#include <cmath>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
size_t findClosestToPi(std::vector<double> const& x)
{
    if (x.empty()) return 0;               // undefined case – follow current contract

    const double pi = M_PI;
    const std::size_t N = x.size();

    // Structure that gathers both the minimum distance and the corresponding index
    struct Closest {
        double dist;
        std::size_t idx;
    };

    Closest result{ std::abs(x[0] - pi), 0 };

    // Parallel reduction to find the smallest absolute difference
    #pragma omp parallel
    {
        Closest local = result;                     // each thread starts with the global best
        #pragma omp for nowait
        for (std::size_t i = 1; i < N; ++i) {
            double d = std::abs(x[i] - pi);
            if (d < local.dist) {
                local.dist = d;
                local.idx  = i;
            }
        }

        // Merge local results into the global one
        #pragma omp critical
        {
            if (local.dist < result.dist) {
                result.dist = local.dist;
                result.idx  = local.idx;
            }
        }
    }

    return result.idx;
}
```

This version:

1. Uses `#pragma omp` to parallelise the scan across available threads.
2. Performs a reduction by keeping a local `Closest` structure per thread and merging them in a critical section.
3. Keeps the same semantics and return type as the original function.
4. Includes necessary headers for `M_PI` and `abs`.

