#pragma once
#include <algorithm>
#include <cstddef>
#include <vector>
#include <omp.h>

/* Sorts the non‑zero elements of the vector in ascending order, leaving
 * the zero values in their original positions.  The implementation
 * avoids unnecessary allocations, uses a single pass to collect the
 * non‑zero elements, and reconstructs the result in a second pass.
 */
inline void sortIgnoreZero(std::vector<int> &x)
{
    const std::size_t n = x.size();
    if (n <= 1) return;

    // Reserve once to avoid intermediate re‑allocations
    std::vector<int> nz;
    nz.reserve(n);

    // Gather non‑zero values
    for (std::size_t i = 0; i < n; ++i) {
        const int v = x[i];
        if (v != 0) nz.push_back(v);
    }

    // Sort the extracted values
    std::sort(nz.begin(), nz.end());

    // Re‑insert sorted values, skipping zeros
    std::size_t nz_idx = 0;
    for (std::size_t i = 0; i < n; ++i) {
        if (x[i] != 0) {
            x[i] = nz[nz_idx++];
        }
    }
}
