/*
 * Count the number of Cartesian points in each quadrant.
 * The vector 'points' contains a list of `Point` objects.
 * Store the counts in 'bins' (order: Q1, Q2, Q3, Q4).
 *
 * This implementation uses OpenMP parallelism to fully utilize
 * the 8 available threads on a modern x86‑64 CPU and eliminates
 * branch mispredictions by using a small lookup table.
 */
void countQuadrants(std::vector<Point> const& points,
                    std::array<std::size_t, 4> &bins)
{
    /* Reset the result array */
    bins.fill(0);

    /* Parallel region – each thread keeps a private count array.
       A single critical section merges the per‑thread results. */
#pragma omp parallel
    {
        std::array<std::size_t, 4> local{0, 0, 0, 0};

#pragma omp for
        for (std::size_t i = 0; i < points.size(); ++i) {
            const auto &p = points[i];

            /* Encode quadrant as two bits:
               bit 1 – sign of x  (1 if negative)
               bit 0 – sign of y  (1 if negative)
               Result codes:
               0b00 → Q1
               0b01 → Q4
               0b10 → Q2
               0b11 → Q3
            */
            unsigned int idx = (unsigned int)((p.x < 0) << 1) | (unsigned int)(p.y < 0);

            /* Increment the appropriate counter. */
            if (idx == 0)           local[0]++;   // Q1
            else if (idx == 1)      local[3]++;   // Q4
            else if (idx == 2)      local[1]++;   // Q2
            else /* idx == 3 */     local[2]++;   // Q3
        }

#pragma omp critical
        {
            for (int j = 0; j < 4; ++j) bins[j] += local[j];
        }
    }
}
