#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

namespace detail {

//---------------------------------------------------------------------------
// Helper: compute bit‑reverse of an uint32 up to log2(N) bits
//---------------------------------------------------------------------------

inline uint32_t bit_reverse(uint32_t v, uint32_t logN)
{
    v = ((v >> 1) & 0x55555555) | ((v & 0x55555555) << 1);
    v = ((v >> 2) & 0x33333333) | ((v & 0x33333333) << 2);
    v = ((v >> 4) & 0x0f0f0f0f) | ((v & 0x0f0f0f0f) << 4);
    v = ((v >> 8) & 0x00ff00ff) | ((v & 0x00ff00ff) << 8);
    v = (v >> 16) | (v << 16);
    return v >> (32 - logN);
}

//---------------------------------------------------------------------------
// Pre‑compute twiddle factors
//---------------------------------------------------------------------------

struct TwiddleTable
{
    std::vector<std::complex<double>> values;

    explicit TwiddleTable(std::size_t n)
    {
        values.resize(n);
        const double pi = std::acos(-1.0);
        for (std::size_t i = 0; i < n; ++i)
        {
            double angle = -2.0 * pi * i / static_cast<double>(n);
            values[i] = std::complex<double>(std::cos(angle), std::sin(angle));
        }
    }
};

//---------------------------------------------------------------------------
// In‑place radix‑2 Cooley‑Tukey FFT (complex, real‑positive twiddle)
// Optimised for speed (single precision complex arithmetic, no CRT)
//---------------------------------------------------------------------------

inline void fft_inplace(std::vector<std::complex<double>>& data)
{
    const std::size_t N = data.size();
    if (N <= 1) return;

    // Log2(N)
    std::size_t logN = 0;
    for (std::size_t temp = N; temp > 1; temp >>= 1) ++logN;

    // Bit‑reversal permutation
    #pragma omp parallel for schedule(static, 8192)
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = bit_reverse(static_cast<uint32_t>(i), static_cast<uint32_t>(logN));
        if (j > i) std::swap(data[i], data[j]);
    }

    // Pre‑compute twiddle table for each stage size
    std::vector<TwiddleTable> tables;
    tables.reserve(logN);
    for (std::size_t stage = 1; stage <= logN; ++stage)
        tables.emplace_back(1ull << stage);

    // Butterfly operations
    for (std::size_t stage = 1, step = 1; stage <= logN; ++stage, step <<= 1)
    {
        const std::size_t stride = 2 * step;
        const std::size_t tblIdx = stage - 1;
        const std::size_t tblSize = tables[tblIdx].values.size();

        #pragma omp parallel for schedule(static, 512)
        for (std::size_t k = 0; k < N; k += stride)
        {
            for (std::size_t j = 0; j < step; ++j)
            {
                std::complex<double> t = tables[tblIdx].values[j * tblSize / (2 * step)]
                                         * data[k + j + step];
                std::complex<double> u = data[k + j];
                data[k + j]      = u + t;
                data[k + j + step] = u - t;
            }
        }
    }
}

//---------------------------------------------------------------------------
// Conjugate the sequence: conj(x[n]) = x[(-n) mod N]
// Compute FFT of conjugated sequence without extra memory
//---------------------------------------------------------------------------

inline void fft_conjugate(std::vector<std::complex<double>>& x)
{
    // Compute the forward FFT
    fft_inplace(x);

    // Reverse all but the first element and conjugate
    const std::size_t N = x.size();
    if (N > 1)
    {
        #pragma omp parallel for schedule(static, 512)
        for (std::size_t i = 1; i < (N + 1) / 2; ++i)
        {
            std::complex<double> tmp = std::conj(x[i]);
            x[i] = std::conj(x[N - i]);
            x[N - i] = tmp;
        }
    }

    // Finally conjugate whole array
    #pragma omp parallel for schedule(static, 1024)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}

} // namespace detail

//---------------------------------------------------------------------------
// Public interface compatible with original harness
//---------------------------------------------------------------------------

void fftConjugate(std::vector<std::complex<double>>& x)
{
    detail::fft_conjugate(x);
}
