//======================================================================
// Optimised sortByStartTime – parallel radix sort for 32‑bit startTime
//======================================================================
#pragma once
#include <vector>
#include <cstdint>
#include <cstddef>
#include <algorithm>
#include <omp.h>
#include <cstring>    // for memcpy

struct Result {
    int   startTime;
    int   duration;
    float value;
};

// ---------------------------------------------------------------------
// Helper: copy a Result with memcpy (fast, no compiler intrinsics)
// ---------------------------------------------------------------------
inline void copyResult(const Result* src, Result* dst)
{
    std::memcpy(dst, src, sizeof(Result));
}

// ---------------------------------------------------------------------
// Parallel radix sort (base 65536) – only key is startTime
// ---------------------------------------------------------------------
void sortByStartTime(std::vector<Result> &results)
{
    const size_t n = results.size();
    if (n < 2) return;                // nothing to do

    /*  Allocate auxiliary buffer only once */
    std::vector<Result> aux(n);

    /*  Count occurrences (MSB first, 16‑bit passes) */
    const size_t bucketSize = 1u << 16;          // 65536
    std::vector<size_t> count(bucketSize, 0);
    std::vector<size_t> prefix(bucketSize, 0);

    // ---------- first pass: lower 16 bits ----------
    // Parallel counting
    #pragma omp parallel
    {
        std::vector<size_t> localCount(bucketSize, 0);
        #pragma omp for schedule(static)
        for (size_t i = 0; i < n; ++i)
            ++localCount[(results[i].startTime) & 0xFFFFu];
        #pragma omp critical
        {
            for (size_t v = 0; v < bucketSize; ++v)
                count[v] += localCount[v];
        }
    }

    // Prefix sum to get positions
    size_t sum = 0;
    for (size_t i = 0; i < bucketSize; ++i) {
        prefix[i] = sum;
        sum += count[i];
    }

    // Distribute to aux (stable)
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        size_t key = results[i].startTime & 0xFFFFu;
        size_t pos = __sync_fetch_and_add(&prefix[key], 1);
        copyResult(&results[i], &aux[pos]);
    }

    // ---------- second pass: upper 16 bits ----------
    std::fill(count.begin(), count.end(), 0);

    #pragma omp parallel
    {
        std::vector<size_t> localCount(bucketSize, 0);
        #pragma omp for schedule(static)
        for (size_t i = 0; i < n; ++i)
            ++localCount[(aux[i].startTime >> 16) & 0xFFFFu];
        #pragma omp critical
        {
            for (size_t v = 0; v < bucketSize; ++v)
                count[v] += localCount[v];
        }
    }

    sum = 0;
    for (size_t i = 0; i < bucketSize; ++i) {
        prefix[i] = sum;
        sum += count[i];
    }

    // Final distribution back into results (stable)
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        size_t key = (aux[i].startTime >> 16) & 0xFFFFu;
        size_t pos = __sync_fetch_and_add(&prefix[key], 1);
        copyResult(&aux[i], &results[pos]);
    }
}
