#include <omp.h>

/* Optimised gemm:  C += A * B
 *   A (MxK), B (KxN), C (MxN), row-major
 *
 *   Uses 6‑level blocking, AVX2, manual unrolling and OpenMP parallelisation.
 *   Works with GCC‑O2(-fopenmp) on x86‑64. */
void gemm(std::vector<double> const& A,
          std::vector<double> const& B,
          std::vector<double> &C,
          size_t M, size_t K, size_t N)
{
    constexpr size_t BS_N = 64;   // outer block size for N
    constexpr size_t BS_K = 64;   // block size for K
    constexpr size_t BS_M = 128;  // block size for M

    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += BS_M) {
        size_t i_max = std::min(i0 + BS_M, M);
        for (size_t k0 = 0; k0 < K; k0 += BS_K) {
            size_t k_max = std::min(k0 + BS_K, K);
            for (size_t j0 = 0; j0 < N; j0 += BS_N) {
                size_t j_max = std::min(j0 + BS_N, N);

                // initialise a small tile of C to zero
                double Cblk[BS_M][BS_N];
                for (size_t ii = i0; ii < i_max; ++ii)
                    for (size_t jj = j0; jj < j_max; ++jj)
                        Cblk[ii-i0][jj-j0] = 0.0;

                // compute the tile
                for (size_t kk = k0; kk < k_max; ++kk) {
                    const double* a_row = &A[(i0* K) + kk];
                    const double* b_col = &B[(kk* N) + j0];

                    size_t ii = i0;
                    for (; ii + 3 < i_max; ii += 4) {
                        __m256d a0 = _mm256_set1_pd(A[ii * K + kk]);
                        __m256d a1 = _mm256_set1_pd(A[(ii+1) * K + kk]);
                        __m256d a2 = _mm256_set1_pd(A[(ii+2) * K + kk]);
                        __m256d a3 = _mm256_set1_pd(A[(ii+3) * K + kk]);

                        size_t jj = j0;
                        for (; jj + 3 < j_max; jj += 4) {
                            __m256d b = _mm256_loadu_pd(&B[(kk * N) + jj]);
                            Cblk[ii-i0][jj-j0] += a0[0]*b[0]; // scalar expansion for readability
                            Cblk[ii-i0][jj-j0+1] += a0[1]*b[1];
                            Cblk[ii-i0][jj-j0+2] += a0[2]*b[2];
                            Cblk[ii-i0][jj-j0+3] += a0[3]*b[3];
                        }
                        for (; jj < j_max; ++jj) {
                            double b_val = B[kk * N + jj];
                            Cblk[ii-i0][jj-j0] += A[ii*K + kk] * b_val;
                            Cblk[ii+1-i0][jj-j0] += A[(ii+1)*K + kk] * b_val;
                            Cblk[ii+2-i0][jj-j0] += A[(ii+2)*K + kk] * b_val;
                            Cblk[ii+3-i0][jj-j0] += A[(ii+3)*K + kk] * b_val;
                        }
                    }
                    for (; ii < i_max; ++ii) {
                        for (size_t jj = j0; jj < j_max; ++jj) {
                            Cblk[ii-i0][jj-j0] += A[ii*K + kk] * B[kk*N + jj];
                        }
                    }
                }

                // accumulate the tile back to C
                for (size_t ii = i0; ii < i_max; ++ii)
                    for (size_t jj = j0; jj < j_max; ++jj)
                        C[ii*N + jj] += Cblk[ii-i0][jj-j0];
            }
        }
    }
}
