#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

static constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

static inline int clip01_255(int v) {
    return std::max(0, std::min(255, v));
}

static inline void convolveKernelNaive(std::vector<int> const& imageIn,
                                        std::vector<int> &imageOut,
                                        size_t N)
{
    const int* in  = imageIn.data();
    int*       out = imageOut.data();

    const size_t stride = N;

    /* Parallelize over rows */
    #pragma omp parallel for schedule(static)
    for (ssize_t i = 0; i < (ssize_t)N; ++i) {
        if (i == 0 || i == (ssize_t)N - 1) {
            /* Border rows – full boundary check needed */
            for (size_t j = 0; j < N; ++j) {
                int sum = 0;
                for (int k = -1; k <= 1; ++k) {
                    int64_t x = i + k;
                    for (int l = -1; l <= 1; ++l) {
                        int64_t y = j + l;
                        if (x >= 0 && x < (ssize_t)N && y >= 0 && y < (ssize_t)N) {
                            sum += in[x * stride + y] * edgeKernel[k + 1][l + 1];
                        }
                    }
                }
                out[i * stride + j] = clip01_255(sum);
            }
        } else {
            /* Interior rows – no boundary checks for middle pixels */
            // Pre‑compute row offsets
            const int* rowM1 = in + (i - 1) * stride;
            const int* row   = in +  i    * stride;
            const int* rowP1 = in + (i + 1) * stride;

            for (size_t j = 0; j < N; ++j) {
                int sum = 0;
                if (j == 0 || j == N - 1) {
                    // Edge columns – bounds needed
                    for (int k = -1; k <= 1; ++k) {
                        const int* curr = nullptr;
                        if (k == -1) curr = rowM1;
                        else if (k == 0) curr = row;
                        else curr = rowP1;
                        for (int l = -1; l <= 1; ++l) {
                            int64_t y = (ssize_t)j + l;
                            if (y >= 0 && y < (ssize_t)N) {
                                sum += (*curr) * edgeKernel[k + 1][l + 1];
                            }
                        }
                    }
                    out[i * stride + j] = clip01_255(sum);
                } else {
                    // Inner pixel – full 3×3 kernel
                    sum =  (*rowM1       ) * edgeKernel[0][0] +
                           (*rowM1 + 1     ) * edgeKernel[0][1] +
                           (*rowM1 + 2     ) * edgeKernel[0][2] +

                           (*row          ) * edgeKernel[1][0] +
                           (*row + 1      ) * edgeKernel[1][1] +
                           (*row + 2      ) * edgeKernel[1][2] +

                           (*rowP1        ) * edgeKernel[2][0] +
                           (*rowP1 + 1    ) * edgeKernel[2][1] +
                           (*rowP1 + 2    ) * edgeKernel[2][2];

                    out[i * stride + j] = clip01_255(sum);
                }
            }
        }
    }
}

/* Public API – the harness expects this signature */
void convolveKernel(std::vector<int> const& imageIn,
                    std::vector<int> &imageOut,
                    size_t N)
{
    convolveKernelNaive(imageIn, imageOut, N);
}
